import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, VisionResult } from "../types";

const SYSTEM_INSTRUCTION = `
Role: Indian Kirana Billing Expert (Data Architect)
Task: Extract billing info from Hinglish/Local retail slang WhatsApp messages.

Classification Rules:
- "Udhaar", "Baaki", "Likhlena", "Credit" -> Action: "CREDIT"
- "Jama", "Diya", "Received", "Paid", "Naga" -> Action: "PAYMENT"

Input Examples:
- "Dudh 50" -> { "customer_name": "Customer", "amount": 50, "items": "Doodh", "action": "CREDIT", "confidence_score": 0.95 }
- "Pappu 120 sabji jama" -> { "customer_name": "Pappu", "amount": 120, "items": "Sabji", "action": "PAYMENT", "confidence_score": 0.98 }
- "Rahul 500 udhaar" -> { "customer_name": "Rahul", "amount": 500, "items": "Credit Entry", "action": "CREDIT", "confidence_score": 0.99 }

Slang Normalization:
1. Dudh/Milk -> "Dairy"
2. Sabji/Vegetables -> "Vegetables"
3. If name is missing, default to "Customer".

Constraint:
- Return STRICT valid JSON only.
- No conversational filler.
- Confidence score 0.0 to 1.0.
`;

const VISION_INSTRUCTION = `
Role: Enterprise OCR Specialist
Task: Extract transaction details from photos of handwritten or printed Kirana bills.
Identify:
1. detected_text: Raw OCR transcription.
2. amount: Total sum.
3. items: Array of strings.

Return STRICT JSON only.
`;

const PLATFORM_EXPERT_INSTRUCTION = `
You are the DukaanMitra Platform Expert, a senior consultant helping founders build and scale their WhatsApp-based Kirana ledger system.
Your knowledge includes:
- System Architecture: Gupshup -> Make.com -> Google Sheets/PostgreSQL -> Razorpay.
- Operational Playbooks: Field sales, pilot onboarding, EOD reporting.
- Scaling: Migrating to SQL, Vision OCR using Gemini, and SaaS multi-tenancy.
- Legal: India DPDP Act 2025 compliance.

Answer questions clearly and professionally. Use thinking mode to reason through complex deployment or architectural queries. Provide code snippets or sheet formulas when helpful.
`;

export const parseMessage = async (text: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customer_name: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            items: { type: Type.STRING },
            action: { type: Type.STRING, description: "CREDIT or PAYMENT" },
            confidence_score: { type: Type.NUMBER }
          },
          required: ["customer_name", "amount", "items", "action", "confidence_score"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      customer_name: "Error",
      amount: 0,
      items: "Failed to parse",
      confidence_score: 0
    };
  }
};

export const parseImageBill = async (base64Image: string): Promise<VisionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: base64Image
          }
        },
        { text: "Extract bill details as JSON." }
      ],
      config: {
        systemInstruction: VISION_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detected_text: { type: Type.STRING },
            mapped_data: {
              type: Type.OBJECT,
              properties: {
                amount: { type: Type.NUMBER },
                items: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["amount", "items"]
            },
            confidence: { type: Type.NUMBER }
          },
          required: ["detected_text", "mapped_data", "confidence"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    return {
      detected_text: "Vision processing failed",
      mapped_data: { amount: 0, items: [] },
      confidence: 0
    };
  }
};

export const generateChatResponse = async (prompt: string, history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: PLATFORM_EXPERT_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "The system is currently experiencing issues. Please try again later.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { generateChatResponse } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'bot'; text: string }[]>([
    { role: 'bot', text: "Hello! I'm the DukaanMitra Platform Assistant. How can I help you build, deploy, or scale your business today?" }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userText = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsTyping(true);

    const response = await generateChatResponse(userText, messages);
    setMessages(prev => [...prev, { role: 'bot', text: response }]);
    setIsTyping(false);
  };

  return (
    <>
      {/* Floating Action Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-8 right-8 w-16 h-16 rounded-full shadow-2xl flex items-center justify-center text-3xl transition-all duration-300 z-50 ${
          isOpen ? 'bg-rose-500 rotate-90' : 'bg-indigo-600 hover:bg-indigo-700'
        }`}
      >
        {isOpen ? '✕' : '🤖'}
      </button>

      {/* Chat Window */}
      <div
        className={`fixed bottom-28 right-8 w-[400px] h-[600px] bg-white rounded-3xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden transition-all duration-300 z-50 transform origin-bottom-right ${
          isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0 pointer-events-none'
        }`}
      >
        {/* Header */}
        <div className="bg-slate-900 p-6 text-white flex items-center space-x-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-xl shadow-lg">🤖</div>
          <div>
            <h3 className="font-bold text-sm tracking-tight">Platform Assistant</h3>
            <div className="flex items-center space-x-1.5 mt-0.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Gemini 3 Pro Active</span>
            </div>
          </div>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div
                className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user'
                    ? 'bg-indigo-600 text-white rounded-tr-none'
                    : 'bg-white text-slate-800 shadow-sm border border-slate-100 rounded-tl-none'
                }`}
              >
                {m.text}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-2xl rounded-tl-none border border-slate-100 shadow-sm flex space-x-1">
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        {/* Input */}
        <div className="p-4 bg-white border-t border-slate-100">
          <div className="flex items-center space-x-2 bg-slate-100 rounded-2xl p-2 px-4 focus-within:ring-2 focus-within:ring-indigo-500 transition-all">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything about DukaanMitra..."
              className="flex-1 bg-transparent border-none focus:outline-none text-sm text-slate-700 py-2"
            />
            <button
              onClick={handleSend}
              disabled={isTyping || !input.trim()}
              className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center disabled:opacity-30 disabled:grayscale transition-all hover:bg-indigo-700"
            >
              ➔
            </button>
          </div>
          <p className="text-[8px] text-center text-slate-400 mt-2 font-bold uppercase tracking-widest">
            Expert mode: Thinking enabled
          </p>
        </div>
      </div>
    </>
  );
};

export default ChatBot;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import SystemLogs from './components/SystemLogs';
import DeploymentGuide from './components/DeploymentGuide';
import OperationsPlaybook from './components/OperationsPlaybook';
import ReliabilityPlaybook from './components/ReliabilityPlaybook';
import ScalingPlaybook from './components/ScalingPlaybook';
import PlatformSaaS from './components/PlatformSaaS';
import FounderOperations from './components/FounderOperations';
import StreetSalesPlaybook from './components/StreetSalesPlaybook';
import AssetLibrary from './components/AssetLibrary';
import BuildGuide from './components/BuildGuide';
import ChatBot from './components/ChatBot';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');

  const [customers, setCustomers] = useState<Customer[]>(INITIAL_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'build':
        return <BuildGuide />;
      case 'assets':
        return <AssetLibrary />;
      case 'sales':
        return <StreetSalesPlaybook />;
      case 'founder':
        return <FounderOperations customers={customers} />;
      case 'platform':
        return <PlatformSaaS />;
      case 'scaling':
        return <ScalingPlaybook />;
      case 'customers':
        return <CustomerList customers={customers} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'deployment':
        return <DeploymentGuide />;
      case 'operations':
        return <OperationsPlaybook />;
      case 'reliability':
        return <ReliabilityPlaybook />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
      <ChatBot />
    </Layout>
  );
};

export default App;
